Function: // handleAppendEntries processes a replication message from the leader.
func (n *Node) handleAppendEntries(msg Msg, electionTimer *time.Timer) {
	n.mu.Lock()
	n.leader = msg.From
	n.role = Follower
	n.mu.Unlock()

	electionTimer.Reset(n.randomElectionTimeout())

	// Log replication logic
	// Reject if we have a newer term
	n.mu.RLock()
	myTerm := n.term
	n.mu.RUnlock()
	if myTerm > msg.Term {
		n.transport.Send(Msg{
			Type:    MsgAppendResp,
			From:    n.ID,
			To:      msg.From,
			Success: false,
			Term:    myTerm,
		})
		return
	}

